import { Component, Input, Output, EventEmitter } from '@angular/core';
import { Observable } from 'rxjs';
import { TextStatsService } from '../../services/text-stats.service';
/**
 * FormattersComponent — Child (RIGHT column)
 * ------------------------------------------
 * Does NOT hold text state — it only emits actions UP
 * to the HomeComponent via @Output EventEmitters.
 *
 * The parent handles all text transformations.
 */
@Component({
  selector: 'app-formatters',
  templateUrl: './formatters.component.html',
  styleUrls: ['./formatters.component.css']
})
export class FormattersComponent {

  // Input from Parent
  @Input() textColor: string = '#e8e8f0';

  // Live stats from service — initialized directly as assignments
  wordCount$: Observable<number> = this.statsService.wordCount$;
  charCount$: Observable<number> = this.statsService.charCount$;

  constructor(private statsService: TextStatsService) {}


  // Outputs to Parent

  // Text Operations
  @Output() clearAll           = new EventEmitter<void>();
  @Output() removeExtraSpaces  = new EventEmitter<void>();
  @Output() reverseSentence    = new EventEmitter<void>();
  @Output() removeSpecialChars = new EventEmitter<void>();
  @Output() capitalizeWords    = new EventEmitter<void>();

  // Styling
  @Output() toggleBold         = new EventEmitter<void>();
  @Output() toggleItalic       = new EventEmitter<void>();
  @Output() toggleUnderline    = new EventEmitter<void>();
  @Output() colorChange        = new EventEmitter<string>();
  @Output() removeStyling      = new EventEmitter<void>();

  // Font Size
  @Output() increaseFontSize   = new EventEmitter<void>();
  @Output() decreaseFontSize   = new EventEmitter<void>();

  /** Relay color picker native event up to parent */
  onColorInput(event: Event): void {
    const input = event.target as HTMLInputElement;
    this.colorChange.emit(input.value);
  }
}
<div class="panel formatters-panel">
  <!-- STATS PANEL — above all operations -->
  <section class="stats-section">
    <h3 class="section-label">Live Stats</h3>
    <div class="stats-grid">
      <div class="stat-card">
        <span class="stat-value">{{ wordCount$ | async }}</span>
        <span class="stat-label">Words</span>
      </div>
      <div class="stat-card">
        <span class="stat-value">{{ charCount$ | async }}</span>
        <span class="stat-label">Characters</span>
      </div>
    </div>
  </section>

  <div class="panel-title">
    <span>Operations</span>
  </div>

  <!-- TEXT OPERATIONS -->
  <section class="section">
    <h3 class="section-label">Text</h3>
    <div class="btn-grid">

      <button class="btn btn-danger" (click)="clearAll.emit()" title="Clear all text">
        <span class="btn-icon">✕</span> Clear All
      </button>

      <button class="btn" (click)="removeExtraSpaces.emit()" title="Collapse multiple spaces">
        <span class="btn-icon">⎵</span> Remove Spaces
      </button>

      <button class="btn" (click)="reverseSentence.emit()" title="Reverse word order">
        <span class="btn-icon">⇆</span> Reverse
      </button>

      <!-- Uses RemoveSpecialCharsPipe internally in parent -->
      <button class="btn" (click)="removeSpecialChars.emit()" title="Strip special characters">
        <span class="btn-icon">∅</span> No Specials
      </button>

      <button class="btn btn-wide" (click)="capitalizeWords.emit()" title="Capitalize every word">
        <span class="btn-icon">Aa</span> Capitalize Words
      </button>

    </div>
  </section>

  <!-- STYLING -->
  <section class="section">
    <h3 class="section-label">Styling</h3>
    <div class="btn-grid">

      <button class="btn" (click)="toggleBold.emit()" title="Toggle bold">
        <strong>B</strong>&nbsp;Bold
      </button>

      <button class="btn" (click)="toggleItalic.emit()" title="Toggle italic">
        <em>I</em>&nbsp;Italic
      </button>

      <button class="btn" (click)="toggleUnderline.emit()" title="Toggle underline">
        <span style="text-decoration:underline">U</span>&nbsp;Underline
      </button>

      <!-- Color Picker: label wraps hidden input -->
      <label class="btn color-btn" title="Pick text color">
        <span class="btn-icon">🎨</span> Color
        <span class="color-swatch" [style.background]="textColor"></span>
        <input
          type="color"
          class="color-input"
          [value]="textColor"
          (input)="onColorInput($event)"
          aria-label="Text color picker">
      </label>

      <button class="btn btn-ghost btn-wide" (click)="removeStyling.emit()" title="Reset all styles">
        <span class="btn-icon">◌</span> Reset Styling
      </button>

    </div>
  </section>

  <!-- FONT SIZE -->
  <section class="section">
    <h3 class="section-label">Font Size</h3>
    <div class="font-size-controls">

      <button class="btn size-btn" (click)="decreaseFontSize.emit()" aria-label="Decrease font size">
        <span class="size-icon">−</span>
      </button>

      <span class="size-label">Aa</span>

      <button class="btn size-btn" (click)="increaseFontSize.emit()" aria-label="Increase font size">
        <span class="size-icon">+</span>
      </button>

    </div>
  </section>

</div>
